    -int id
  }
  class DroneChargingSlot {
    -int id
    -float outputPower
  }
  class DroneParkingSlot {
    -int id
  }
  class PharmacyService {
    +PharmacyService()
    +addPharmacy(name, pharmacyManager, latitude, longitude, streetName, doorNumber, postalCode, locality, country)
    +registerPharmacy()
  }
}

